import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';

// Importando os SVGs
import bitcoinLogo from '../../assets/crypto_logos/bitcoin.svg';
import ethereumLogo from '../../assets/crypto_logos/ethereum.svg';
import litecoinLogo from '../../assets/crypto_logos/litecoin.svg';
import rippleLogo from '../../assets/crypto_logos/ripple.svg';
import cardanoLogo from '../../assets/crypto_logos/cardano.svg';
import polkadotLogo from '../../assets/crypto_logos/polkadot.svg';
import chainlinkLogo from '../../assets/crypto_logos/chainlink.svg';
import binanceLogo from '../../assets/crypto_logos/binance.svg';
import solanaLogo from '../../assets/crypto_logos/solana.svg';
import dogecoinLogo from '../../assets/crypto_logos/dogecoin.svg';
// Adicione mais importações de logos conforme necessário

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [displayText, setDisplayText] = useState('');
  const [isTyping, setIsTyping] = useState(true);
  const [showDots, setShowDots] = useState(false);

  const fullText = 'Nautilus Automação';
  const typingSpeed = 150;
  const pauseTime = 10000;

  // Array de logos SVG importados
  const cryptoLogos = [
    bitcoinLogo,
    ethereumLogo,
    litecoinLogo,
    rippleLogo,
    cardanoLogo,
    polkadotLogo,
    chainlinkLogo,
    binanceLogo,
    solanaLogo,
    dogecoinLogo,
    // Adicione mais variáveis de logos importados aqui
  ];

  // Array extenso de símbolos de criptomoedas e blockchain
  const cryptoSymbols = [
    // Símbolos principais de criptomoedas
    '₿', 'Ξ', '⟠', 'Ł', '◊', '⧫', '◈', '◇', '⬟', '⬢', '⬡', '⬠',
    // Símbolos matemáticos e geométricos relacionados
    '⟐', '⟡', '⟢', '⟣', '⟤', '⟥', '⟦', '⟧', '⟨', '⟩', '⟪', '⟫', '⟬', '⟭',
    // Símbolos de moedas e financeiros
    '¤', '₳', '₴', '₵', '₶', '₷', '₸', '₹', '₺', '₻', '₼', '₽', '₾', '₿',
    // Símbolos de blockchain e tecnologia
    '⬢', '⬡', '⬠', '⬟', '⬞', '⬝', '⬜', '⬛', '⭐', '⭑', '⭒', '⭓', '⭔', '⭕',
    // Símbolos geométricos avançados
    '◆', '◇', '◈', '◉', '◊', '○', '◌', '◍', '◎', '●', '◐', '◑', '◒', '◓',
    // Símbolos de setas e direcionais
    '↗', '↘', '↙', '↖', '↕', '↔', '⇄', '⇅', '⇆', '⇇', '⇈', '⇉', '⇊', '⇋',
    // Símbolos de estrelas e formas
    '★', '☆', '✦', '✧', '✩', '✪', '✫', '✬', '✭', '✮', '✯', '✰', '✱', '✲',
    // Símbolos de tecnologia e digital
    '⚡', '⚙', '⚛', '⚜', '⚝', '⚞', '⚟', '⚠', '⚡', '⚢', '⚣', '⚤', '⚥', '⚦',
    // Símbolos adicionais de criptomoedas conhecidas
    'Ð', 'Ł', 'Ξ', '₳', 'Ⱥ', 'Ƀ', 'Ȼ', 'Đ', 'Ɇ', 'Ƒ', 'Ǥ', 'Ħ', 'Ɨ', 'Ɉ',
    // Símbolos de redes e conexões
    '⌘', '⌬', '⌭', '⌮', '⌯', '⌰', '⌱', '⌲', '⌳', '⌴', '⌵', '⌶', '⌷', '⌸',
    // Símbolos de segurança e criptografia
    '🔐', '🔑', '🔒', '🔓', '🔔', '🔕', '🔖', '🔗', '🔘', '🔙', '🔚', '🔛', '🔜', '🔝',
    // Símbolos de gráficos e análise
    '📈', '📉', '📊', '📋', '📌', '📍', '📎', '📏', '📐', '📑', '📒', '📓', '📔', '📕'
  ];

  useEffect(() => {
    let timeoutId;
    let currentIndex = 0;

    const typeText = () => {
      if (currentIndex <= fullText.length) {
        setDisplayText(fullText.slice(0, currentIndex));
        currentIndex++;
        timeoutId = setTimeout(typeText, typingSpeed);
      } else {
        setIsTyping(false);
        setShowDots(true);
        timeoutId = setTimeout(() => {
          setShowDots(false);
          setIsTyping(true);
          setDisplayText('');
          currentIndex = 0;
          typeText();
        }, pauseTime);
      }
    };

    typeText();

    return () => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
    };
  }, []);

  // Removido - não precisamos mais da animação de fundo

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Limpar erro quando o usuário começar a digitar
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Validação básica
    if (!formData.email || !formData.password) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    // Validação simples de email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    try {
      const result = await login(formData.email, formData.password);

      if (result.success) {
        toast.success('Login realizado com sucesso!');
      } else {
        setError(result.message || 'Erro ao fazer login');
        toast.error(result.message || 'Erro ao fazer login');
      }
    } catch (error) {
      console.error('Erro no login:', error);
      setError('Erro ao fazer login. Tente novamente.');
      toast.error('Erro ao fazer login');
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <Box
      sx={{
        position: 'relative',
        minHeight: '100vh',
        overflow: 'hidden',
        background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)'
      }}
    >
      {/* Background com símbolos flutuantes */}
      <Box
        sx={{
          position: 'fixed', // Mantém fixo para cobrir a tela toda
          top: 0,
          left: 0,
          width: '100vw', // Usa vw para largura total da viewport
          height: '100vh', // Usa vh para altura total da viewport
          zIndex: 1, // Garante que está atrás do conteúdo
          overflow: 'hidden', // Essencial para não criar barras de rolagem
          pointerEvents: 'none' // Para não interferir com cliques no formulário
        }}
      >
        {generateFloatingSymbols()}
      </Box>

      {/* CSS para animações */}
      <style>
        {`
          @keyframes blink {
            0%, 50% { opacity: 1; }
            51%, 100% { opacity: 0; }
          }
          @keyframes blinkDots {
            0%, 33% { opacity: 1; }
            34%, 66% { opacity: 0.5; }
            67%, 100% { opacity: 0; }
          }
          @keyframes moveUp {
            0% {
              transform: translateY(0px) translateX(-50%);
              opacity: 0.8;
            }
            50% {
              transform: translateY(-50px) translateX(-50%);
              opacity: 1;
            }
            100% {
              transform: translateY(-100px) translateX(-50%);
              opacity: 0.8;
            }
          }

          @keyframes rotate {
            0% {
              transform: rotate(0deg);
            }
            100% {
              transform: rotate(360deg);
            }
          }
        `}
      </style>

      <Container maxWidth="sm" sx={{ position: 'relative', zIndex: 10 }}>
        <Box
          sx={{
            minHeight: '100vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            py: 4
          }}
        >
          <Paper
            elevation={8}
            sx={{
              p: 4,
              width: '100%',
              maxWidth: 400,
              bgcolor: 'rgba(255, 255, 255, 0.95)',
              borderRadius: 2,
              backdropFilter: 'blur(10px)'
            }}
          >
            {/* Logo/Título */}
            <Box sx={{ textAlign: 'center', mb: 4 }}>
              <Typography
                variant="h5"
                component="h1"
                sx={{
                  fontWeight: 'bold',
                  color: '#1976d2', // Cor azul
                  mb: 1,
                  minHeight: '2rem', // Altura mínima para evitar saltos
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '1.5rem',
                  whiteSpace: 'nowrap'
                }}
              >
                {displayText}
                {isTyping && (
                  <Box
                    component="span"
                    sx={{
                      display: 'inline-block',
                      width: '2px',
                      height: '1.2em',
                      backgroundColor: '#1976d2',
                      marginLeft: '2px',
                      animation: 'blink 1s infinite'
                    }}
                  />
                )}
                {showDots && (
                  <Box
                    component="span"
                    sx={{
                      color: '#1976d2',
                      marginLeft: '8px',
                      animation: 'blinkDots 1.5s infinite'
                    }}
                  >
                    ...
                  </Box>
                )}
              </Typography>
              <Typography
                variant="subtitle1"
                color="text.secondary"
              >
                Faça login em sua conta
              </Typography>
            </Box>

            {/* Formulário */}
            <Box component="form" onSubmit={handleSubmit}>
              {error && (
                <Alert severity="error" sx={{ mb: 2 }}>
                  {error}
                </Alert>
              )}

              <TextField
                fullWidth
                name="email"
                label="Email"
                type="email"
                value={formData.email}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="email"
                autoFocus
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Email color="action" />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    '&:hover fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                    '&.Mui-focused fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#1976d2', // Cor azul
                  },
                }}
              />

              <TextField
                fullWidth
                name="password"
                label="Senha"
                type={showPassword ? 'text' : 'password'}
                value={formData.password}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="current-password"
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Lock color="action" />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={togglePasswordVisibility}
                        edge="end"
                        aria-label="toggle password visibility"
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    '&:hover fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                    '&.Mui-focused fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#1976d2', // Cor azul
                  },
                }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                disabled={loading}
                sx={{
                  mt: 3,
                  mb: 2,
                  py: 1.5,
                  fontSize: '1rem',
                  fontWeight: 'bold',
                  bgcolor: '#1976d2', // Cor azul
                  color: 'white',
                  '&:hover': {
                    bgcolor: '#1565c0', // Azul mais escuro no hover
                  },
                  '&:disabled': {
                    bgcolor: 'action.disabled',
                  },
                }}
              >
                {loading ? (
                  <CircularProgress size={24} color="inherit" />
                ) : (
                  'Entrar'
                )}
              </Button>

              {/* Link para registro */}
              <Box sx={{ textAlign: 'center', mt: 2 }}>
                <Typography variant="body2" color="text.secondary">
                  Não tem uma conta?{' '}
                  <Link
                    component={RouterLink}
                    to="/register"
                    sx={{
                      color: '#1976d2', // Cor azul
                      textDecoration: 'none',
                      fontWeight: 'bold',
                      '&:hover': {
                        textDecoration: 'underline',
                      },
                    }}
                  >
                    Registre-se
                  </Link>
                </Typography>
              </Box>
            </Box>
          </Paper>
        </Box>
      </Container>
    </Box>
  );
};

export default Login;
